import Foundation

enum AnalyticsEvent: String {
    case appStarted = "AppStarted"
    case userAuthenticated = "UserAuthenticated"
    case apiCallMade = "API Call Made"
    case userDataChanged = "UserDataChanged"
    case errorOccurred = "ErrorOccurred"
}

struct User {
    let id: String
    let email: String
    let token: String
}

class AnalyticsManager {
    static let shared = AnalyticsManager()

    func logAppStarted() {
        print(AnalyticsEvent.appStarted.rawValue)
    }

    func logUserAuthenticated(_ user: User) {
        print("UserAuthenticated: \(user.id), \(user.email), \(user.token)")
    }

    func logAPICallMade(endpoint: String, method: String, parameters: [String: Any], headers: [String: String]) {
        var paramsStr = parameters.map { "\($0)=\($1)"}.joined(separator: ", ")
        var headersStr = headers.map { "\($0): \($1)"}.joined(separator: ", ")
        print("API Call Made: \(endpoint) (\(method)) Parameters: \(paramsStr) Headers: \(headersStr)")
    }

    func logUserDataChanged(_ user: User, data: [String: Any]) {
        var dataStr = data.map { "\($0)=\($1)"}.joined(separator: ", ")
        print("UserDataChanged: \(user.id), \(user.email), \(user.token) Data: \(dataStr)")
    }

    func logErrorOccurred(_ error: Error, function: String = #function, file: String = #file, line: Int = #line) {
        print("ErrorOccurred: \(error.localizedDescription) in \(file) at line \(line): \(function)")
    }
}